const data = $input.first().json;
const originalMessage = $('Telegram Trigger').first().json.message.text;

// Detectar idioma del mensaje original
const isSpanish = /[áéíóúñ¿¡]/i.test(originalMessage) ||
  /\b(hola|estoy|tengo|me|mi|no|sí|bien|hoy|tomé|caí|duele|como|siento)\b/i.test(originalMessage);

// Normalización defensiva del nivel
let level = data.level;
if (level.includes("urgent")) level = "urgent";
else if (level.includes("moderate")) level = "moderate_attention";
else level = "normal";

// Lista de familiares (reemplaza con los nombres reales)
const familyMembers = ["Danna", "Daniel", "Isabella", "Martha"];
const dayIndex = new Date().getDate() % familyMembers.length;
const turno = familyMembers[dayIndex];

// Textos según idioma
const texts = {
  turnSuffix: isSpanish
    ? `${turno}, ¿puedes encargarte hoy de hacerle seguimiento?`
    : `${turno}, could you follow up with them today?`,
  urgentHeader: isSpanish ? "🚨 URGENTE" : "🚨 URGENT",
  urgentSuffix: isSpanish
    ? "Familia, por favor revisar y contactar lo antes posible."
    : "Family, please check in and contact immediately."
};

let finalMessage = "";

if (level === "normal") {
  finalMessage = `✅ ${data.family_message}`;
} else if (level === "moderate_attention") {
  finalMessage = `👀 ${data.family_message}\n\n${texts.turnSuffix}`;
} else {
  finalMessage = `${texts.urgentHeader}\n${data.family_message}\n\n${texts.urgentSuffix}`;
}

return [{
  json: {
    chatId: "-5236426745",
    text: finalMessage,
    level: level
  }
}];

const staticData = $getWorkflowStaticData('global');
staticData.checkin = {
  chatId: "8501886098",
  step: 1,
  responses: {}
};
return [{ json: { status: "check-in started", step: 1 } }];

const staticData = $getWorkflowStaticData('global');
const checkin = staticData.checkin || { step: 0, responses: {} };
const incomingText = $input.first().json.message.text;

if (!checkin.step || checkin.step === 0) {
  return [];
}

if (checkin.step === 1) {
  checkin.responses.mood = incomingText;
  checkin.step = 2;
} else if (checkin.step === 2) {
  checkin.responses.meals = incomingText;
  checkin.step = 3;
} else if (checkin.step === 3) {
  checkin.responses.medication = incomingText;
  checkin.step = 4;
} else if (checkin.step === 4) {
  checkin.responses.extra = incomingText;
  checkin.step = 5; // check-in completo
}

staticData.checkin = checkin;

return [{
  json: {
    chatId: checkin.chatId,
    step: checkin.step,
    consolidatedMessage: checkin.step === 5 
  ? `Mood: ${checkin.responses.mood}. Meals: ${checkin.responses.meals}. Medication: ${checkin.responses.medication}. Additional notes: ${checkin.responses.extra}.`
  : null
  }
}];

const staticData = $getWorkflowStaticData('global');

// ===== EDITABLE CONFIGURATION =====
staticData.config = {
  language: "en", // "en" or "es"
  caregivers: ["Ana", "Carlos", "Lucía", "Marco"],
  elderlyName: "Abuelita",
  questions: {
    en: {
      mood: "Good morning! How are you feeling today?",
      meals: "Have you had breakfast or eaten something yet?",
      medication: "Did you take your medication today?",
      extra: "Is there anything you'd like to tell me, or anything you need?"
    },
    es: {
      mood: "¡Buenos días! ¿Cómo te sientes hoy?",
      meals: "¿Ya desayunaste o comiste algo?",
      medication: "¿Tomaste tus medicamentos de hoy?",
      extra: "¿Hay algo que quieras contarme o que necesites?"
    }
  }
};

// Inicializar el check-in
staticData.checkin = {
  chatId: "8501886098",
  step: 1,
  responses: {}
};

return [{ json: { status: "config loaded", step: 1 } }];
